var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"으엥~","JPN":"ひいい～ん。","ENG":"Hnngg...","TWN":"呃嗯～"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"간신히 절반지점까지 헤엄쳤는데 억지로 끌려 나왔어.","JPN":"やっと半分まで泳いだのに、むりやり引き上げられたぁ。","ENG":"I was finally halfway to the end. Why did you pull me out?","TWN":"好不容易游了一半，結果卻被強行拉上岸了。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"미, 미안합니다. 전 혹시나 물에 빠진 줄 알고......","JPN":"ご、ごめんなさい。てっきり溺れたのかと思って……","ENG":"I-I'm sorry. I thought you were drowning...","TWN":"對、對不起，我以為妳溺水了……"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"아니에요. 그런 자세로 헤엄을 치고 있으면 당연히 오해를 살 수 밖에 없죠.","JPN":"いいえ。変な姿勢で泳いでたので、誤解されて当然です。","ENG":"Don't be. Of course you thought she was drowning.","TWN":"沒關係。用那種姿勢游泳，不被誤會才怪。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"어차피 저런 식이면 레인 끝에 도착하기도 전에 탈진했을 테니 잘 해주셨어요.","JPN":"どうせあんな姿勢じゃ、プールの端に到着する前に気力が尽きていたと思うので、よくやってくれました。","ENG":"Swimming like that, she would have exhausted herself before reaching the other end. Thank you for helping her.","TWN":"反正用那種方式繼續游的話，還沒到終點就會虛脫的，所以妳做得很好。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"이디스, 그렇게 팔다리를 막무가내로 휘젓는 수영은 비효율적입니다.","JPN":"イーディス、そんなに手足を無駄に振り回す泳ぎ方は非効率的です。","ENG":"Edith, flailing your limbs like that isn't an effective way of swimming.","TWN":"伊蒂絲，在水裡亂抓亂扒是沒有效率的游泳方式。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"다시 가르쳐줄 테니 이번엔 제대로......","JPN":"もう一度教えますから、今回はちゃんと……","ENG":"Let me teach you again. This time, we will—","TWN":"我再教妳一次，這次要認真學……"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"으으, 열심히 헤엄쳤더니 너무 졸려~ 더는 못해~","JPN":"うう、頑張って泳いだから眠すぎる～もうダメ～。","ENG":"Ugh, I swam too hard. I'm toooo tired. I can't do it anymooore.","TWN":"呃，我游到沒力氣了，好睏喔～我游不下去了～"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"......쿠울......","JPN":"……すやすや……","ENG":"Zzz...","TWN":"……呼……"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"어머? 선 채로 잠들었네요? 저런 게 정말로 가능하구나.","JPN":"あれ？　立ったまま眠ってしまいましたね？　あんなのって本当にできるんだ。","ENG":"Oh, she fell asleep standing up. I didn't know that was possible.","TWN":"哎呀？竟然站著睡著了呢？真是太神奇了。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"......제 연구조교 시절을 떠올리게 하는 모습이로군요.","JPN":"……私が研究所で助手だった頃を思い出しますね。","ENG":"She reminds me of myself when I was an assistant researcher.","TWN":"……這簡直就像我助教時代的樣子呢。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"잠깐 앉혀두면 곧 깨어날 겁니다. 걱정 마시길.","JPN":"しばらく座らせておいたらすぐ起きますよ。心配しないでください。","ENG":"Let her sit on her chair for a while, and she'll wake up soon. Don't worry.","TWN":"讓她坐一會兒很快會醒來的，不用擔心。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"제 이름은 옌 싱 란체스터라고 해요. 두 분은 호텔의 투숙객들이군요?","JPN":"私の名前はイェン・シング・ランチェスターと申します。お二人はホテルの宿泊客ですよね？","ENG":"My name is Yen Xing Lanchester. Are you two staying at the hotel?","TWN":"我叫嫣杏·蘭賈斯特，兩位是飯店的入住客人吧？"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"어머, 어떻게 아셨어요?","JPN":"おや、どうやって知ったんですか？","ENG":"Oh, how did you know?","TWN":"咦，妳是怎麼知道的？"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"후훗, 학교의 안위를 책임지려면 학교 주변의 소식에도 밝아야 하니까요.","JPN":"ふふっ、学校の安全を担う人間として、学校周辺の状況もいろいろと知っておく必要がありますから。","ENG":"Hah hah. As someone in charge of the peace of my school, I must be aware of what's going on around it at all times.","TWN":"呵呵，為了維護學校安全，必須掌握周邊的訊息才行。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"침식체가 나타났다고 들었는데, 다행히 잘 해결된 모양이네요.","JPN":"侵食体が現れたと聞いたんですが、無事に解決できたようですね。","ENG":"I heard some C.O.s showed up. Someone must have taken good care of them.","TWN":"我聽說有侵蝕體出沒，但所幸事情似乎都順利解決了。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"두 분은 어쩐 일로 여기 오게 되셨나요?","JPN":"お二人はどのようなご用件でここに来たんですか？","ENG":"May I ask what brings you two to this school?","TWN":"那你們兩位來這裡是有什麼事嗎？"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"아, 저희는 운명적인 모험을 하고 있어요.","JPN":"あ、私たちは運命的な冒険をしてるんです。","ENG":"Oh, we're on a fateful adventure.","TWN":"啊，我們正在進行命運之冒險。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};